var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"정말, 제가 도와드릴 것이 있나요?","JPN":"本当に私がお手伝いできることがあるんですか？","ENG":"Really? There’s something that I can help you with?","TWN":"真的，有我幫得上忙的地方嗎？"},"stage":{"bg":"CAR","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그래. 어쩌면 이제는 자네만이 할 수 있는 일이지.","JPN":"ああ。今となっては君にしかできないことだろう。","ENG":"That is correct. In fact, you may be the only one who can help me with it now.","TWN":"當然，這個忙或許只有你能幫呢。"},"stage":{"bg":"CAR","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"남은 시간이 별로 많지 않거든.","JPN":"残された時間があまりないからね。","ENG":"You see, there isn’t a lot of time.","TWN":"現在已經沒剩多少時間，"},"stage":{"bg":"CAR","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그리고 우리의 적들은…… 무척 강하다네.","JPN":"それに私たちの敵は……とても強い。","ENG":"Our enemies... They’re very strong.","TWN":"而且我們的敵人……非常強。"},"stage":{"bg":"CAR","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"적이요? 사장님처럼 착한 분께요?","JPN":"敵ですか？　社長のようにお優しい方に？","ENG":"Enemies? Even someone as kind as you has enemies?","TWN":"敵人？像老闆這麼好的人也會有敵人嗎？"},"stage":{"bg":"CAR","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"그렇다면 정말 나쁜 사람들이겠네요.","JPN":"だとしたら、本当に悪い人たちに違いありませんね。","ENG":"Then they must be very bad people.","TWN":"那對方應該真的很壞吧？"},"stage":{"bg":"CAR","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하하, 그냥 나쁜 사람들과는 조금 다르다네.","JPN":"ハハ、単に悪い人というのとは少し違うんだ。","ENG":"Haha, they are more than just \\"bad people\\".","TWN":"哈哈，他們和一般認知的壞人不太一樣，"},"stage":{"bg":"CAR","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그들은 마왕, 혹은 악마라고 불리는 초월적인 존재들이니까.","JPN":"やつらは魔王、あるいは悪魔と呼ばれる超越的な存在だからね。","ENG":"They are transcendent beings called demon lords, or devils.","TWN":"他們是被稱為魔王或惡魔的超自然存在。"},"stage":{"bg":"CAR","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"마왕이요?","JPN":"魔王ですか？","ENG":"Demon lords?","TWN":"魔王嗎？"},"stage":{"bg":"CAR","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"신기해라. 마치 동화 속 이야기 같아요.","JPN":"不思議。まるで童話の中のお話みたいです。","ENG":"That’s so interesting. It’s like something out of a fairy tale.","TWN":"好奇妙喔，好像童話故事一樣。"},"stage":{"bg":"CAR","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"좋은 비유로군.","JPN":"いい例えだ。","ENG":"That’s a good analogy.","TWN":"這個說法不錯。"},"stage":{"bg":"CAR","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그러면 지아 양, 동화에서 마왕을 쓰러트리기 위해서는 뭐가 필요하겠나?","JPN":"それでは、ユイさん。童話で魔王を倒すためには何が必要かな？","ENG":"So, Miss Jia, what do the heroes in fairy tales need for defeating demon lords?","TWN":"沈佳，那我問你，在童話故事中，打倒魔王需要什麼呢？"},"stage":{"bg":"CAR","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"음…… 보통은 마법의 검이나 신비한 무기 아닐까요?","JPN":"う～ん……一般的には魔法の剣とか神秘的な武器でしょうか？","ENG":"Hmm... Wouldn’t it usually be a magical sword or mystical weapon?","TWN":"嗯……通常不是魔劍，就是秘密武器吧？"},"stage":{"bg":"CAR","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"바로 그것일세.","JPN":"まさにそれだ。","ENG":"That’s exactly what we need.","TWN":"沒錯，就是那個！"},"stage":{"bg":"CAR","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하지만 그런 무기들은 오직 특별한 존재, 주인공만이 사용할 수 있지.","JPN":"だが、そんな武器は特別な存在である主人公だけが使えるものだ。","ENG":"However, weapons like that can only be used by special beings, which are the main heroes.","TWN":"不過那個武器很特別，只有主角能夠使用。"},"stage":{"bg":"CAR","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그리고 현실은 동화와는 달라서, 아주 많은 마왕이 존재한다네.","JPN":"そして現実は童話とは違って、あまたの魔王が存在する。","ENG":"Also, reality differs from fairy tales, and there are many demon lords in our world.","TWN":"而且現實和童話故事是不一樣的，現實中有非常多的魔王。"},"stage":{"bg":"CAR","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그러면 우리에게 필요한 건……","JPN":"だとしたら、我々に必要なのは……","ENG":"So, what we need is...","TWN":"因此我們需要的是……"},"stage":{"bg":"CAR","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"더 많은 무기로군요!","JPN":"それを超える数の武器ですね！","ENG":"More weapons!","TWN":"更多的武器！"},"stage":{"bg":"CAR","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}}]`);export{e as default};